xpath.script:
(function() {
    var d = document.documentElement;
    d.dataset.novaMode = '';
    d.dataset.novaAccent = '';
    d.dataset.novaAnimations = '';
    d.dataset.novaSidebarCollapsed = '';
    d.dataset.novaFontSize = '';
    d.dataset.novaFontFamily = '';
    var m = d.dataset.novaMode;
    if (m === 'dark' || (m === 'auto' && window.matchMedia('(prefers-color-scheme: dark)').matches)) {
        d.classList.add('nova-dark');
    }
})();

div.script:
(function() {
    var el = document.getElementById('nova-skeleton');
    if (!el) return;
    // Skeleton is only for the backend webclient (/web#...)
    // On portal/frontend pages, remove it immediately
    var path = window.location.pathname;
    if (path !== '/web' && path !== '/web/' && path.indexOf('/web?') !== 0) {
        el.remove();
        return;
    }
    var h = window.location.hash || '';
    var vt = (h.match(/view_type=(\w+)/i) || [])[1];
    var model = (h.match(/model=([^&]+)/i) || [])[1] || '';
    // Settings pages are form views but look nothing like forms
    var settingsModels = /^(res\.config\.settings|base\.setup\.installer)$/;
    if (vt === 'form' && settingsModels.test(model)) {
        vt = 'list';
    }
    el.dataset.view = vt ? vt.toLowerCase() : 'list';
    // Kanban: detect grouped (pipeline) vs ungrouped (grid)
    if (el.dataset.view === 'kanban') {
        var grouped = /^(project\.task|crm\.lead|crm\.opportunity|helpdesk\.ticket|project\.project)$/.test(model);
        el.dataset.kanban = grouped ? 'grouped' : 'ungrouped';
    }
    if (el.dataset.hasSidebar === 'true') {
        var collapsed = document.documentElement.dataset.novaSidebarCollapsed === 'True';
        el.dataset.sidebar = collapsed ? 'collapsed' : 'expanded';
    }
})();
